      "content": "const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with optional filters and pagination.
   * When includeComponents=true, include componentLanguageTotals and componentStatusTotals
   * that reflect counts for the filtered and limited result set.
   *
   * @param {Object} options
   * @param {boolean} options.includeComponents - whether to include component totals
   * @param {number} options.limit - max number of problems to return
   * @param {string[]} options.tags - filter problems by tags
   * @param {string} options.difficulty - filter problems by difficulty
   * @returns {Object} response with problems and metadata
   */
  static listProblems({ includeComponents = false, limit = 50, tags = [], difficulty = null } = {}) {
    // Filter problems by tags and difficulty
    let filtered = problemsData;

    if (tags.length > 0) {
      filtered = filtered.filter(problem =>
        tags.every(tag => problem.tags && problem.tags.includes(tag))
      );
    }

    if (difficulty) {
      filtered = filtered.filter(problem => problem.difficulty === difficulty);
    }

    // Apply limit
    const limited = filtered.slice(0, limit);

    // Prepare metadata
    const metadata = {};

    if (includeComponents) {
      // Aggregate language totals and status totals for the limited set
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      limited.forEach(problem => {
        if (problem.components && Array.isArray(problem.components)) {
          problem.components.forEach(component => {
            // Count by language
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Count by status
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      metadata.componentLanguageTotals = componentLanguageTotals;
      metadata.componentStatusTotals = componentStatusTotals;
    }

    return {
      problems: limited,
      metadata
    };
  }
}

module.exports = ProblemsService;
